changeSet.sql:
CREATE TABLE "regulator_notice"
(
    "id"           BIGINT       NOT NULL,
    "process_type" VARCHAR(256) NOT NULL,

    CONSTRAINT "pk_regulator_notice" PRIMARY KEY ("id"),
    CONSTRAINT "fk_regulator_notice_task" FOREIGN KEY ("id")
        REFERENCES "task" ("id")
);

CREATE INDEX regulator_notice_process_type_idx
    ON regulator_notice(process_type);

COMMENT
ON TABLE "regulator_notice" IS 'Regulator Notice';
COMMENT
ON COLUMN "regulator_notice"."process_type" IS 'The type of the process';

alter table account add column if not exists selling_allowances boolean default false;
alter table account add column if not exists sales_contact_uka_1_99 boolean default false;
alter table account add column if not exists sales_contact_uka_100_999 boolean default false;
alter table account add column if not exists sales_contact_uka_1000_plus boolean default false;

rollback.sql:
